code = """import json
import os

# Load the AGMH 2019 data
var_key = 'var_functions.query_db:26'
file_path = locals().get(var_key)

if file_path and isinstance(file_path, str) and os.path.exists(file_path):
    with open(file_path, 'r') as f:
        agmh_data = json.load(f)
else:
    agmh_data = []

print(f"Loaded {len(agmh_data)} trading days for AGMH in 2019")

# Calculate volatile days for AGMH
volatile_days = 0
volatile_days_list = []

for day in agmh_data:
    high = float(day['High'])
    low = float(day['Low'])
    
    # Calculate intraday range
    intraday_range = high - low
    
    # Calculate 20% of low price
    twenty_percent_low = 0.20 * low
    
    # Check if range exceeds 20% of low price
    if intraday_range > twenty_percent_low:
        volatile_days += 1
        volatile_days_list.append({
            'Date': day['Date'],
            'High': high,
            'Low': low,
            'Range': intraday_range,
            '20pct_Low': twenty_percent_low
        })

print(f"AGMH volatile days in 2019: {volatile_days}")
print(f"Sample volatile day: {volatile_days_list[:3] if volatile_days_list else 'None'}")

result = {
    "ticker": "AGMH",
    "volatile_days": volatile_days,
    "total_days": len(agmh_data),
    "sample_volatile_days": volatile_days_list[:3],
    "has_volatiles": volatile_days > 0
}

print(f"__RESULT__:")
print(json.dumps(result))"""

